import { useMemo, useState } from "react";
import { TablePreview } from "../../components/tables/TablePreview";
import { useTableData, type TableQuery } from "./useTableData";
import { tableConfig, type Row } from "./tableConfig";
import { useRowInteractions } from "./useRowInteractions";

/**
 * Server-driven DataTable wrapper.
 *
 * `useTableData` also exposes `refetch`, `error` and feature-aware mutators
 * (`updateCell`, `deleteRows`, `reorderRows`) plus any typed row-action
 * handlers — destructure them when you want to wire custom UI on top of
 * TablePreview:
 *
 *   const { data, loading, refetch, updateCell } = useTableData<Row>(...)
 */
export default function ServerCrmTable() {
  const [search] = useState("");
  const [filters] = useState<Record<string, string>>({});
  const [sorts] = useState<Array<{ key: string; dir: "asc" | "desc" }>>([]);
  const [page] = useState(0);
  const [pageSize] = useState(tableConfig.pageSize ?? 10);

  const query = useMemo<TableQuery>(() => ({
      search,
      filters,
      sorts,
      page,
      pageSize,
  }), [search, filters, sorts, page, pageSize]);

  const { data, loading } = useTableData<Row>(tableConfig.apiEndpoint!, query);
  // Typed per-column change handlers — see useRowInteractions.ts.
  const { onCellInteract } = useRowInteractions<Row>();

  return (
    <TablePreview
      config={tableConfig}
      data={data}
      isLoading={loading}
      onCellInteract={onCellInteract}
    />
  );
}

import { useCallback, useEffect, useState } from "react";
import type { Row } from "./tableConfig";

/**
 * Server-driven data hook for this DataTable.
 *
 * List endpoint (table-wide search / sort / filter / pagination):
 *   GET `https://api.example.com/contacts`
 *
 * Row-action endpoints (per-row mutations from interactive cells like
 * dropdown / switch / radio / checkbox / rating / button — INDEPENDENT
 * of the list endpoint and target a single row at a time):
 *   PATCH `${endpoint}/:id/stage`  ← dropdown on column "stage"
 *   PATCH `${endpoint}/:id/priority`  ← dropdown on column "priority"
 *   POST `${endpoint}/:id/refresh`  ← button on column "actions"
 *
 * Only the inputs, mutators and handlers your enabled features need are
 * emitted — no dead state, no unused destructures.
 */
export interface TableQuery {
  page: number;
  pageSize: number;
  search: string;
  filters: Record<string, string>;
  sorts: Array<{ key: string; dir: "asc" | "desc" }>;
}

export interface UseTableData<TRow extends { id: string }> {
  data: TRow[];
  total: number;
  loading: boolean;
  error: Error | null;
  refetch: () => Promise<void>;
  updateCell: (rowId: string, key: keyof TRow, value: unknown) => Promise<void>;
  deleteRows: (ids: ReadonlyArray<string>) => Promise<void>;
  reorderRows: (orderedIds: ReadonlyArray<string>) => Promise<void>;
  onDropdownStage: (row: TRow, value: unknown) => Promise<void>;
  onDropdownPriority: (row: TRow, value: unknown) => Promise<void>;
  onButtonActions: (row: TRow) => Promise<void>;
}

const baseHeaders: Record<string, string> = {};

export function useTableData<TRow extends { id: string } = Row>(
  endpoint: string,
  query: TableQuery,
): UseTableData<TRow> {
  const [data, setData] = useState<TRow[]>([]);
  const [total, setTotal] = useState<number>(0);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<Error | null>(null);

  const refetch = useCallback(async (): Promise<void> => {
    setLoading(true);
    setError(null);
    const ctrl = new AbortController();
    try {
      const params = new URLSearchParams();
      params.set("page", String(query.page));
      params.set("size", String(query.pageSize));
      if (query.search) params.set("q", query.search);
      for (const [k, v] of Object.entries(query.filters)) {
        if (v) params.set(`filter[${k}]`, v);
      }
      query.sorts.forEach((s, i) => params.append(`sort[${i}]`, `${s.key}:${s.dir}`));
      const res = await fetch(`${endpoint}?${params}`, { method: "GET", headers: baseHeaders, signal: ctrl.signal });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = (await res.json()) as { data: TRow[]; total: number } | TRow[];
      const list = Array.isArray(json) ? json : json.data;
      setData(list);
      setTotal(Array.isArray(json) ? list.length : (json.total ?? list.length));
    } catch (e) {
      if ((e as Error).name !== "AbortError") {
        setError(e instanceof Error ? e : new Error("Unknown error"));
      }
    } finally {
      setLoading(false);
    }
  }, [endpoint, query.page, query.pageSize, query.search, query.filters, query.sorts]);

  useEffect(() => { void refetch(); }, [refetch]);

  /** PATCH `${endpoint}/:rowId` — update a single cell value. */
  const updateCell = useCallback(async (rowId: string, key: keyof TRow, value: unknown): Promise<void> => {
    const res = await fetch(`${endpoint}/${rowId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json", ...baseHeaders },
      body: JSON.stringify({ [key]: value }),
    });
    if (!res.ok) throw new Error(`updateCell failed: ${res.status}`);
    setData(prev => prev.map(r => (r.id === rowId ? ({ ...r, [key]: value } as TRow) : r)));
  }, [endpoint]);

  /** POST `${endpoint}/bulk-delete` — delete N rows in a single request. */
  const deleteRows = useCallback(async (ids: ReadonlyArray<string>): Promise<void> => {
    const res = await fetch(`${endpoint}/bulk-delete`, {
      method: "POST",
      headers: { "Content-Type": "application/json", ...baseHeaders },
      body: JSON.stringify({ ids }),
    });
    if (!res.ok) throw new Error(`deleteRows failed: ${res.status}`);
    setData(prev => prev.filter(r => !ids.includes(r.id)));
    setTotal(t => Math.max(0, t - ids.length));
  }, [endpoint]);

  /** POST `${endpoint}/reorder` — persist a new row order. */
  const reorderRows = useCallback(async (orderedIds: ReadonlyArray<string>): Promise<void> => {
    const res = await fetch(`${endpoint}/reorder`, {
      method: "POST",
      headers: { "Content-Type": "application/json", ...baseHeaders },
      body: JSON.stringify({ order: orderedIds }),
    });
    if (!res.ok) throw new Error(`reorderRows failed: ${res.status}`);
  }, [endpoint]);

  /**
   * PATCH `${endpoint}/:id/stage` — dropdown action for column "stage".
   * Fired from the cell renderer whenever the user changes the value (or
   * clicks, for trigger="button"). This is a per-row mutation and is
   * INDEPENDENT from the table list endpoint.
   */
  const onDropdownStage = useCallback(async (row: TRow, value: unknown): Promise<void> => {
    setData(prev => prev.map(r => r.id === row.id ? ({ ...r, ["stage"]: value } as TRow) : r));
    const rollback = () => setData(prev => prev.map(r => r.id === row.id ? row : r));
    try {
      const res = await fetch(`${endpoint}/${row.id}/stage`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json", ...baseHeaders },
        body: "{ \"stage\": {{value}}, \"previous\": {{row.stage}} }".replace(/{{value}}/g, JSON.stringify(value)).replace(/{{rowId}}/g, JSON.stringify(row.id)).replace(/{{row\.(\w+)}}/g, (_, k) => JSON.stringify((row as Record<string, unknown>)[k])),
      });
      if (!res.ok) throw new Error(`onDropdownStage failed: ${res.status}`);
    } catch (e) {
      rollback();
      throw e;
    }
  }, [endpoint]);


  /**
   * PATCH `${endpoint}/:id/priority` — dropdown action for column "priority".
   * Fired from the cell renderer whenever the user changes the value (or
   * clicks, for trigger="button"). This is a per-row mutation and is
   * INDEPENDENT from the table list endpoint.
   */
  const onDropdownPriority = useCallback(async (row: TRow, value: unknown): Promise<void> => {
    setData(prev => prev.map(r => r.id === row.id ? ({ ...r, ["priority"]: value } as TRow) : r));
    const rollback = () => setData(prev => prev.map(r => r.id === row.id ? row : r));
    try {
      const res = await fetch(`${endpoint}/${row.id}/priority`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json", ...baseHeaders },
        body: "{ \"priority\": {{value}} }".replace(/{{value}}/g, JSON.stringify(value)).replace(/{{rowId}}/g, JSON.stringify(row.id)).replace(/{{row\.(\w+)}}/g, (_, k) => JSON.stringify((row as Record<string, unknown>)[k])),
      });
      if (!res.ok) throw new Error(`onDropdownPriority failed: ${res.status}`);
    } catch (e) {
      rollback();
      throw e;
    }
  }, [endpoint]);


  /**
   * POST `${endpoint}/:id/refresh` — button action for column "actions".
   * Fired from the cell renderer whenever the user changes the value (or
   * clicks, for trigger="button"). This is a per-row mutation and is
   * INDEPENDENT from the table list endpoint.
   */
  const onButtonActions = useCallback(async (row: TRow): Promise<void> => {
    try {
      const res = await fetch(`${endpoint}/${row.id}/refresh`, {
        method: "POST",
        headers: { "Content-Type": "application/json", ...baseHeaders },
        body: JSON.stringify({ id: row.id }),
      });
      if (!res.ok) throw new Error(`onButtonActions failed: ${res.status}`);
    } catch (e) {
      throw e;
    }
  }, [endpoint]);


  return { data, total, loading, error, refetch, updateCell, deleteRows, reorderRows, onDropdownStage, onDropdownPriority, onButtonActions };
}

import { useCallback } from "react";
import type { Row } from "./tableConfig";

/**
 * Per-column user-interaction handlers for this DataTable.
 *
 * One handler per interactive column (dropdown / switch / radio / checkbox /
 * rating). Each receives the full row plus the old and new values so you
 * can react with full context — no extra lookups, no stale closures:
 *
 *   onStageChange(row, oldValue, newValue)  ← "Stage" (dropdown)
 *
 * The hook also exposes a single `onCellInteract(row, key, oldValue, newValue)`
 * dispatcher you can pass straight to <TablePreview onCellInteract={...} />
 * — its signature matches the engine prop exactly and routes each cell
 * change to the matching typed handler above.
 */
export interface UseRowInteractions<TRow extends { id: string }> {
  onStageChange: (row: TRow, oldValue: string, newValue: string) => Promise<void>;
  /**
   * Engine-compatible dispatcher. Signature matches `TablePreviewProps['onCellInteract']`
   * positional argument order: (row, key, oldValue, newValue).
   */
  onCellInteract: (
    row: Record<string, unknown>,
    key: string,
    oldValue: unknown,
    newValue: unknown,
  ) => Promise<void> | void;
}

export function useRowInteractions<TRow extends { id: string } = Row>(): UseRowInteractions<TRow> {
  /**
   * Fires when the user changes the "Stage" cell (type: dropdown).
   * Replace the body with your own logic — call an API, dispatch an action,
   * trigger analytics, persist to a store, etc. The full row is passed in
   * so you have id + every other column value without an extra lookup.
   */
  const onStageChange = useCallback(async (
    row: TRow,
    oldValue: string,
    newValue: string,
  ): Promise<void> => {
    if (oldValue === newValue) return;
    // eslint-disable-next-line no-console
    console.log("[onStageChange]", { rowId: row.id, oldValue, newValue, row });
    // TODO: e.g. await fetch(`/api/rows/${row.id}`, {
    //   method: "PATCH",
    //   headers: { "Content-Type": "application/json" },
    //   body: JSON.stringify({ "stage": newValue }),
    // });
  }, []);

  const onCellInteract = useCallback((
    row: Record<string, unknown>,
    key: string,
    oldValue: unknown,
    newValue: unknown,
  ): Promise<void> | void => {
    switch (key) {
      case "stage":
        return onStageChange(row as TRow, oldValue as string, newValue as string);
      default:
        return;
    }
  }, [onStageChange]);

  return {
    onCellInteract,
    onStageChange,
  };
}
